#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int c;
    while ((c = getchar()) != '\n' && c != EOF); // consume end of line after T
    while (T--) {
        char name[51];
        long long employee_id;
        double salary;
        if (!fgets(name, sizeof(name), stdin)) break;
        name[strcspn(name, "\n")] = '\0';
        if (scanf("%lld", &employee_id) != 1) break;
        if (scanf("%lf", &salary) != 1) break;
        while ((c = getchar()) != '\n' && c != EOF); // consume end of line after salary
        printf("Name: %s ID: %lld Salary: %.2f\n", name, employee_id, salary);
    }
    return 0;
}

