const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
while (idx < lines.length && lines[idx].trim() === '') idx++; // skip possible leading empty lines
const T = parseInt(lines[idx++], 10);
let outputs = [];
for (let i = 0; i < T; i++) {
  const name = lines[idx++] ?? '';
  const employee_id = parseInt(lines[idx++], 10);
  const salary = parseFloat(lines[idx++]);
  outputs.push(`Name: ${name} ID: ${employee_id} Salary: ${salary.toFixed(2)}`);
}
